    const n = nums.length;

    // 1. Find the peak index
    let peakIndex = 0;
    // The array is guaranteed to be bitonic (strictly increasing then strictly decreasing)
    // We can find the peak by iterating until the next element is smaller.
    for (let i = 1; i < n; i++) {
        if (nums[i] > nums[i - 1]) {
            peakIndex = i;
        } else {
            // Once the sequence starts decreasing or stays level (though strict decrease is expected after the peak), 
            // the previous index was the peak, or the current index is the start of the decrease.
            // Since the peak must be the element right before the first decrease, we can stop here.
            break;
        }
