    // Edge case check: If the array is strictly increasing (e.g., [1, 2, 3]), peakIndex will be n-1.
    // If the array is strictly decreasing (not possible given the constraint for n>=3 and bitonic nature, but good to keep in mind), peakIndex would be 0.
    // For a standard bitonic array, the loop finds the correct peak.

    // 2. Calculate the sum of the increasing part (0 to peakIndex, inclusive)
    let sumIncreasing = 0;
    for (let i = 0; i <= peakIndex; i++) {
        sumIncreasing += nums[i];
    }

    // 3. Calculate the sum of the decreasing part (peakIndex to n-1, inclusive)
    let sumDecreasing = 0;
    for (let i = peakIndex; i < n; i++) {
        sumDecreasing += nums[i];
    }

    // 4. Compare the sums and return the result
    if (sumIncreasing > sumDecreasing) {
        return 0; // Increasing part sum is larger
    } else if (sumDecreasing > sumIncreasing) {
        return 1; // Decreasing part sum is larger
    } else {
        return -1; // Sums are equal
    }
}

